615→// =========================================================================
616→// Primary WebSocket handler — creates Gemini Live session
617→// =========================================================================
618→
619→async function handlePrimaryWebSocket(ws: WebSocket, req: IncomingMessage) {
620→  const apiKey = process.env.GOOGLE_API_KEY ?? process.env.GEMINI_API_KEY;
621→  if (!apiKey) {
622→    ws.send(JSON.stringify({ type: "error", message: "No API key configured" }));
623→    ws.close();
624→    return;
625→  }
626→
627→  const sessionId = randomHex(4);
628→  const roomCode = generateRoomCode();
629→  let closed = false;
630→
631→  // Transcription buffers
632→  let bufInput = "";
633→  let bufOutput = "";
634→
635→  // Device registration for primary
636→  const devType = detectDeviceType(req);
637→  const primaryDeviceId = randomHex(4);
638→  const primaryDevice: Device = {
639→    id: primaryDeviceId,
640→    ws,
641→    name: deviceTypeName(devType) + " (Primary)",
642→    deviceType: devType,
643→    isPrimary: true,
644→    roles: { mic: true, midi: false },
645→    connectedAt: Date.now(),
646→  };
647→
648→  console.log(`[${APP_NAME}] Primary connected: ${sessionId}, room: ${roomCode}, device: ${primaryDeviceId}`);
649→
650→  // ---------------------------------------------------------------------------
651→  // Gemini Live API via @google/genai SDK
652→  // ---------------------------------------------------------------------------
653→  const client = new GoogleGenAI({ apiKey });
654→  let session: Session;
655→  let roomSession: RoomSession | null = null;
656→  let audioMsgCount = 0;
657→
658→  const sendAll = (data: Buffer | string, binary = false) => {
659→    if (roomSession) broadcastToRoom(roomSession, data, binary);
660→  };
661→
662→  try {
663→    session = await client.live.connect({
664→      model: LIVE_MODEL,
665→      config: {
666→        responseModalities: [Modality.AUDIO],
667→        systemInstruction: STORYTELLER_INSTRUCTION,
668→        speechConfig: {
669→          voiceConfig: {
670→            prebuiltVoiceConfig: { voiceName: "Puck" },
671→          },
672→        },
673→        inputAudioTranscription: {},
674→        outputAudioTranscription: {},
675→        realtimeInputConfig: {
676→          automaticActivityDetection: {
677→            disabled: false,
678→          },
679→        },
680→        tools: buildToolDeclarations() as any,
681→      },
682→      callbacks: {
683→        onopen: () => {
684→          console.log(`[${APP_NAME}] Gemini Live connected: ${sessionId}`);
685→          roomSession = {
686→            sendRealtimeInput: (input: any) => session.sendRealtimeInput(input),
687→            sendClientContent: (content: any) => session.sendClientContent(content),
688→            primaryWs: ws,
689→            devices: new Map(),
690→            midiBuffer: [],
691→            midiFlushTimer: null,
692→          };
693→          roomSession.devices.set(primaryDeviceId, primaryDevice);
694→          rooms.set(roomCode, roomSession);
695→
696→          ws.send(JSON.stringify({ type: "you_are_primary", room: roomCode, deviceId: primaryDeviceId }));
697→          ws.send(JSON.stringify({ type: "room_code", room: roomCode }));
698→          sendDeviceList(roomSession);
699→
700→          // Send greeting to make Gemini speak first
701→          setTimeout(() => {
702→            if (!closed && session) {
703→              session.sendClientContent({
704→                turns: [{ role: "user", parts: [{ text: "Hi! I just sat down at the piano. Say hello briefly." }] }],
705→                turnComplete: true,
706→              });
707→              console.log(`[${APP_NAME}] Sent greeting to Gemini`);
708→            }
709→          }, 1000);
710→        },
711→        onerror: (e: unknown) => {
712→          console.error(`[${APP_NAME}] Gemini error: ${sessionId}`, e);
713→          try { ws.send(JSON.stringify({ type: "gemini_error", error: String(e) })); } catch {}
714→        },
715→        onclose: () => {
716→          console.error(`[${APP_NAME}] *** Gemini closed: session=${sessionId}`);
717→          closed = true;
718→          try { ws.send(JSON.stringify({ type: "gemini_error", code: 1000, reason: "Session ended" })); } catch {}
719→          try { ws.close(); } catch {}
720→        },
721→        onmessage: (msg: unknown) => {
722→          if (closed || !roomSession) return;
723→          const message = msg as Record<string, unknown>;
724→          const msgKeys = Object.keys(message);
725→
726→          // Log non-audio messages for debugging
727→          if (msgKeys.includes("setupComplete")) {
728→            console.log(`[${APP_NAME}] ${sessionId} setupComplete`);
729→            return;
730→          }
731→
732→          const serverContent = message.serverContent as Record<string, unknown> | undefined;
733→          if (serverContent) {
734→            const modelTurn = serverContent.modelTurn as Record<string, unknown> | undefined;
735→            if (modelTurn?.parts) {
736→              const parts = modelTurn.parts as Array<Record<string, unknown>>;
737→              for (const part of parts) {
738→                const inlineData = part.inlineData as Record<string, unknown> | undefined;
739→                if (inlineData?.data) {
740→                  audioMsgCount++;
741→                  if (audioMsgCount <= 3) console.log(`[${APP_NAME}] ${sessionId} audio chunk #${audioMsgCount}`);
742→                  sendAll(Buffer.from(inlineData.data as string, "base64"), true);
743→                }
744→                // Tool calls
745→                const functionCall = part.functionCall as Record<string, unknown> | undefined;
746→                if (functionCall) {
747→                  const name = functionCall.name as string;
748→                  const args = (functionCall.args as Record<string, unknown>) || {};
749→                  const visualEvent = toolCallToVisualEvent(name, args);
750→                  if (visualEvent) sendAll(JSON.stringify(visualEvent));
751→                  const result = executeToolLocally(name, args);
752→                  const id = functionCall.id as string;
753→                  session.sendToolResponse({ functionResponses: [{ id, name, response: result }] });
754→                  console.log(`[${APP_NAME}] ${sessionId} tool: ${name}`);
755→                }
756→              }
757→            }
758→
759→            // Transcription
760→            const inputTranscription = serverContent.inputTranscription as Record<string, unknown> | undefined;
761→            if (inputTranscription?.text) {
762→              const text = (inputTranscription.text as string).trim();
763→              if (text) {
764→                bufInput = text;
765→                console.log(`[${APP_NAME}] ${sessionId} IN: ${text}`);
766→              }
767→            }
768→            const outputTranscription = serverContent.outputTranscription as Record<string, unknown> | undefined;
769→            if (outputTranscription?.text) {
770→              const text = (outputTranscription.text as string).trim();
771→              if (text) {
772→                bufOutput = text;
773→                console.log(`[${APP_NAME}] ${sessionId} OUT: ${text}`);
774→              }
775→            }
776→
777→            // Turn complete
778→            if (serverContent.turnComplete) {
779→              if (bufInput) { sendAll(JSON.stringify({ type: "input_transcript", text: bufInput })); bufInput = ""; }
780→              if (bufOutput) { sendAll(JSON.stringify({ type: "output_transcript", text: bufOutput })); bufOutput = ""; }
781→              sendAll(JSON.stringify({ type: "turn_complete" }));
782→              console.log(`[${APP_NAME}] ${sessionId} turnComplete (audioChunks=${audioMsgCount})`);
783→            }
784→
785→            // Interrupted
786→            if (serverContent.interrupted) {
787→              if (bufInput) { sendAll(JSON.stringify({ type: "input_transcript", text: bufInput })); bufInput = ""; }
788→              if (bufOutput) { sendAll(JSON.stringify({ type: "output_transcript", text: bufOutput })); bufOutput = ""; }
789→              sendAll(JSON.stringify({ type: "interrupted" }));
790→              console.log(`[${APP_NAME}] ${sessionId} interrupted`);
791→            }
792→          }
793→
794→          // toolCallCancellation
795→          const toolCall = message.toolCall as Record<string, unknown> | undefined;
796→          if (toolCall?.functionCalls) {
797→            const functionCalls = toolCall.functionCalls as Array<Record<string, unknown>>;
798→            for (const fc of functionCalls) {
799→              const name = fc.name as string;
800→              const id = fc.id as string;
801→              const args = (fc.args as Record<string, unknown>) || {};
802→              const visualEvent = toolCallToVisualEvent(name, args);
803→              if (visualEvent) sendAll(JSON.stringify(visualEvent));
804→              const result = executeToolLocally(name, args);
805→              session.sendToolResponse({ functionResponses: [{ id, name, response: result }] });
806→              console.log(`[${APP_NAME}] ${sessionId} toolCall: ${name}`);
807→            }
808→          }
809→        },
810→      },
811→    });
812→  } catch (err) {
813→    console.error(`[${APP_NAME}] Failed to connect Gemini Live:`, err);
814→    ws.send(JSON.stringify({ type: "error", message: "Failed to connect to Gemini" }));
815→    ws.close(1011, "Failed to connect to Gemini");
816→    return;
817→  }
818→
819→  console.log(`[${APP_NAME}] Gemini session ready: ${sessionId}, room: ${roomCode}`);
820→
821→  // ---------------------------------------------------------------------------
822→  // Receive from primary client, forward to Gemini
823→  // ---------------------------------------------------------------------------
824→  try {
825→    for await (const rawMsg of wsMessages(ws)) {
826→      if (closed) break;
827→
828→      if (rawMsg instanceof Buffer || rawMsg instanceof ArrayBuffer) {
829→        if (!primaryDevice.roles.mic) continue;
830→        const data = rawMsg instanceof ArrayBuffer ? new Uint8Array(rawMsg) : rawMsg;
831→        session.sendRealtimeInput({
832→          audio: { data: Buffer.from(data).toString("base64"), mimeType: "audio/pcm;rate=16000" },
833→        });
834→      } else if (typeof rawMsg === "string") {
835→        const msg = JSON.parse(rawMsg);
836→        const msgType = msg.type;
837→
838→        if (msgType === "text") {
839→          session.sendClientContent({
840→            turns: [{ role: "user", parts: [{ text: msg.content }] }],
841→            turnComplete: true,
842→          });
843→        } else if (msgType === "midi_snapshot") {
844→          if (!primaryDevice.roles.midi) continue;
845→          const summary = describeMidiSnapshot(msg);
846→          if (summary) {
847→            session.sendClientContent({
848→              turns: [{ role: "user", parts: [{ text: summary }] }],
849→              turnComplete: true,
850→            });
851→          }
852→        } else if (msgType === "set_mode") {
853→          // Single agent — mode is always storyteller
854→        } else if (msgType === "midi_event") {
855→          // Frontend uses raw MIDI events for UI rendering; snapshots go to agent
856→        } else if (msgType === "set_device_role") {
857→          const { deviceId, role, enabled } = msg;
858→          if (roomSession && (role === "mic" || role === "midi")) {
859→            setDeviceRole(roomSession as RoomSession, deviceId, role, Boolean(enabled));
860→            console.log(`[${APP_NAME}] Role ${role}=${enabled} on device ${deviceId}`);
861→          }
862→        } else if (msgType === "close") {
863→          break;
864→        }
865→      }
866→    }
867→  } catch (e: any) {
868→    if (!closed) console.log(`[${APP_NAME}] receive error:`, e?.message);
869→  }
870→
871→  closed = true;
872→  try { session.close(); } catch {}
873→
874→  // Cleanup
875→  const rs = rooms.get(roomCode);
876→  if (rs?.midiFlushTimer) clearTimeout(rs.midiFlushTimer);
877→  if (rs) {
878→    for (const d of rs.devices.values()) {
879→      if (!d.isPrimary && d.ws.readyState === WebSocket.OPEN) {
880→        try {
881→          d.ws.send(JSON.stringify({ type: "room_closed" }));
882→          d.ws.close();
883→        } catch {}
884→      }
885→    }
886→  }
887→  rooms.delete(roomCode);
888→  console.log(`[${APP_NAME}] Primary disconnected: ${sessionId}, room ${roomCode} removed`);
889→  try { ws.close(); } catch {}
890→}
